import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../utils/api';
import { useAuth } from '../context/AuthContext';

const SAMPLE_PRODUCTS = [
  { name: 'iPhone 15 Pro', description: 'Latest Apple smartphone with A17 chip, titanium design', price: 999, category: 'Electronics', image: 'https://fdn2.gsmarena.com/vv/pics/apple/apple-iphone-15-pro-1.jpg', stock: 30 },
  { name: 'Samsung Galaxy S24', description: 'Android flagship with AI features and stunning display', price: 799, category: 'Electronics', image: 'https://images.samsung.com/in/smartphones/galaxy-s24-ultra/images/galaxy-s24-ultra-highlights-color-titanium-black-back-mo.jpg?imbypass=true', stock: 25 },
  { name: 'MacBook Air M2', description: 'Supercharged by M2 chip, ultra thin and light design', price: 1199, category: 'Electronics', image: 'https://images.unsplash.com/photo-1517336714731-489689fd1ca8?w=400&q=80', stock: 20 },
  { name: 'Sony WH-1000XM5 Headphones', description: 'Industry leading noise cancelling wireless headphones', price: 349, category: 'Electronics', image: 'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=400&q=80', stock: 25 },
  { name: 'Samsung 4K Smart TV 55"', description: 'Crystal clear 4K QLED display with smart features', price: 699, category: 'Electronics', image: 'https://images.unsplash.com/photo-1593359677879-a4bb92f829d1?w=400&q=80', stock: 15 },
  { name: 'Apple AirPods Pro 2', description: 'Active noise cancellation with transparency mode', price: 249, category: 'Electronics', image: 'https://images.unsplash.com/photo-1600294037681-c80b4cb5b434?w=400&q=80', stock: 40 },
  { name: 'iPad Pro 12.9"', description: 'Most powerful iPad ever with M2 chip and Liquid Retina', price: 1099, category: 'Electronics', image: 'https://images.unsplash.com/photo-1544244015-0df4b3ffc6b0?w=400&q=80', stock: 18 },
  { name: 'PlayStation 5 Console', description: 'Next generation gaming console with DualSense controller', price: 499, category: 'Electronics', image: 'https://images.unsplash.com/photo-1607853202273-797f1c22a38e?w=400&q=80', stock: 10 },
  { name: 'Nike Air Max 270', description: 'Lightweight and comfortable daily running shoes', price: 129, category: 'Shoes', image: 'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=400&q=80', stock: 50 },
  { name: 'Adidas Ultraboost 23', description: 'Responsive Boost cushioning for serious runners', price: 189, category: 'Shoes', image: 'https://images.unsplash.com/photo-1608231387042-66d1773070a5?w=400&q=80', stock: 40 },
  { name: 'Nike Air Force 1 Low', description: 'Classic iconic white low top sneakers', price: 109, category: 'Shoes', image: 'https://images.unsplash.com/photo-1491553895911-0055eca6402d?w=400&q=80', stock: 45 },
  { name: 'Converse Chuck Taylor', description: 'Timeless canvas high top sneaker since 1917', price: 69, category: 'Shoes', image: 'https://images.unsplash.com/photo-1463100099107-aa0980c362e6?w=400&q=80', stock: 60 },
  { name: "Levi's 501 Original Jeans", description: 'Original straight fit iconic denim jeans', price: 79, category: 'Clothing', image: 'https://images.unsplash.com/photo-1542272604-787c3835535d?w=400&q=80', stock: 60 },
  { name: 'Ralph Lauren Polo Shirt', description: 'Classic fit short sleeve cotton polo shirt', price: 89, category: 'Clothing', image: 'https://images.unsplash.com/photo-1598032895397-b9472444bf93?w=400&q=80', stock: 45 },
  { name: 'Nike Dri-FIT T-Shirt', description: 'Moisture wicking performance training t-shirt', price: 35, category: 'Clothing', image: 'https://images.unsplash.com/photo-1521572163474-6864f9cf17ab?w=400&q=80', stock: 70 },
  { name: 'Atomic Habits Book', description: 'Tiny Changes Remarkable Results by James Clear', price: 18, category: 'Books', image: 'https://images.unsplash.com/photo-1589829085413-56de8ae18c73?w=400&q=80', stock: 80 },
  { name: 'The Great Gatsby Book', description: 'F. Scott Fitzgerald timeless American classic novel', price: 12, category: 'Books', image: 'https://images.unsplash.com/photo-1544947950-fa07a98d237f?w=400&q=80', stock: 100 },
  { name: 'Yoga Mat Premium 6mm', description: 'Non-slip extra thick exercise yoga mat', price: 49, category: 'Sports', image: 'https://images.unsplash.com/photo-1601925228843-69eb89a77c8a?w=400&q=80', stock: 30 },
  { name: 'Adjustable Dumbbell Set', description: 'Rubber coated adjustable weight dumbbell pair', price: 89, category: 'Sports', image: 'https://images.unsplash.com/photo-1534438327276-14e5300c3a48?w=400&q=80', stock: 20 },
  { name: 'Coffee Maker 12 Cup', description: '12 cup programmable drip coffee maker machine', price: 129, category: 'Home', image: 'https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?w=400&q=80', stock: 25 },
];

const Admin = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [products, setProducts] = useState([]);
  const [orders, setOrders] = useState([]);
  const [tab, setTab] = useState('products');
  const [form, setForm] = useState({ name: '', description: '', price: '', category: '', image: '', stock: '' });
  const [msg, setMsg] = useState('');
  const [loading, setLoading] = useState(false);
  const [seeding, setSeeding] = useState(false);

  useEffect(() => {
    if (!user?.isAdmin) navigate('/');
    fetchProducts();
    fetchOrders();
  }, []);

  const fetchProducts = () => api.get('/products').then(r => setProducts(r.data));
  const fetchOrders = () => api.get('/orders').then(r => setOrders(r.data));

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const handleAddProduct = async e => {
    e.preventDefault();
    setLoading(true);
    try {
      await api.post('/products', { ...form, price: Number(form.price), stock: Number(form.stock) });
      setMsg('✅ Product added!');
      setForm({ name: '', description: '', price: '', category: '', image: '', stock: '' });
      fetchProducts();
    } catch (err) {
      setMsg('❌ ' + (err.response?.data?.message || 'Error'));
    }
    setLoading(false);
  };

  const handleSeedProducts = async () => {
    setSeeding(true);
    setMsg('');
    let count = 0;
    for (const p of SAMPLE_PRODUCTS) {
      try { await api.post('/products', p); count++; } catch (e) {}
    }
    setMsg(`✅ Added ${count} sample products!`);
    fetchProducts();
    setSeeding(false);
  };

  const handleDeleteProduct = async id => {
    if (!window.confirm('Delete this product?')) return;
    await api.delete(`/products/${id}`);
    fetchProducts();
  };

  const handleDeleteAllProducts = async () => {
    if (!window.confirm('Delete ALL products?')) return;
    for (const p of products) {
      try { await api.delete(`/products/${p._id}`); } catch (e) {}
    }
    fetchProducts();
    setMsg('✅ All products deleted!');
  };

  const handleStatusUpdate = async (id, status) => {
    await api.put(`/orders/${id}/status`, { status });
    fetchOrders();
  };

  const statusColor = s => ({
    pending: '#ff9800', processing: '#2196f3',
    shipped: '#9c27b0', delivered: '#4caf50', cancelled: '#f44336'
  }[s] || '#888');

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <h2 style={styles.title}>⚙️ Admin Panel</h2>
        <div style={styles.stats}>
          <div style={styles.stat}><span style={styles.statNum}>{products.length}</span><span style={styles.statLabel}>Products</span></div>
          <div style={styles.stat}><span style={styles.statNum}>{orders.length}</span><span style={styles.statLabel}>Orders</span></div>
          <div style={styles.stat}><span style={styles.statNum}>${orders.reduce((s, o) => s + o.totalPrice, 0).toFixed(0)}</span><span style={styles.statLabel}>Revenue</span></div>
        </div>
      </div>

      <div style={styles.tabs}>
        {['products', 'orders', 'add'].map(t => (
          <button key={t} onClick={() => setTab(t)} style={tab === t ? styles.activeTab : styles.tab}>
            {t === 'products' ? '📦 Products' : t === 'orders' ? '📋 Orders' : '➕ Add Product'}
          </button>
        ))}
      </div>

      {/* ADD PRODUCT */}
      {tab === 'add' && (
        <div style={styles.section}>
          <div style={styles.sectionHeader}>
            <h3>Add New Product</h3>
            <div style={{ display: 'flex', gap: '10px' }}>
              <button onClick={handleDeleteAllProducts} style={styles.deleteAllBtn}>
                🗑 Delete All Products
              </button>
              <button onClick={handleSeedProducts} disabled={seeding} style={styles.seedBtn}>
                {seeding ? '⏳ Adding...' : '🚀 Add 20 Sample Products'}
              </button>
            </div>
          </div>
          {msg && <p style={styles.msg}>{msg}</p>}
          <form onSubmit={handleAddProduct} style={styles.form}>
            <div style={styles.formGrid}>
              {[
                { name: 'name', placeholder: 'Product Name' },
                { name: 'price', placeholder: 'Price (e.g. 99)' },
                { name: 'category', placeholder: 'Category (Electronics, Shoes, etc)' },
                { name: 'stock', placeholder: 'Stock quantity' },
              ].map(f => (
                <input key={f.name} name={f.name} placeholder={f.placeholder}
                  value={form[f.name]} onChange={handleChange} style={styles.input} required />
              ))}
            </div>
            <input name="image" placeholder="Image URL" value={form.image} onChange={handleChange} style={styles.inputFull} />
            <textarea name="description" placeholder="Product description" value={form.description}
              onChange={handleChange} style={styles.textarea} required />
            <button type="submit" disabled={loading} style={styles.submitBtn}>
              {loading ? 'Adding...' : '➕ Add Product'}
            </button>
          </form>
        </div>
      )}

      {/* PRODUCTS LIST */}
      {tab === 'products' && (
        <div style={styles.section}>
          <h3>All Products ({products.length})</h3>
          <div style={styles.productTable}>
            {products.map(p => (
              <div key={p._id} style={styles.productRow}>
                <img src={p.image} alt={p.name} style={styles.thumb}
                  onError={e => { e.target.src = 'https://via.placeholder.com/60'; }} />
                <div style={{ flex: 1 }}>
                  <p style={styles.productName}>{p.name}</p>
                  <p style={styles.productCat}>{p.category}</p>
                </div>
                <span style={styles.productPrice}>${p.price}</span>
                <span style={styles.stockBadge(p.stock)}>Stock: {p.stock}</span>
                <button onClick={() => handleDeleteProduct(p._id)} style={styles.delBtn}>🗑 Delete</button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ORDERS */}
      {tab === 'orders' && (
        <div style={styles.section}>
          <h3>All Orders ({orders.length})</h3>
          {orders.map(o => (
            <div key={o._id} style={styles.orderRow}>
              <div>
                <p style={styles.orderId}>#{o._id.slice(-8)}</p>
                <p style={styles.orderUser}>{o.user?.name || 'Customer'} — {o.user?.email}</p>
                <p style={styles.orderItems}>{o.items.map(i => `${i.name} ×${i.quantity}`).join(', ')}</p>
              </div>
              <div style={styles.orderRight}>
                <p style={styles.orderTotal}>${o.totalPrice.toFixed(2)}</p>
                <p style={styles.orderDate}>{new Date(o.createdAt).toLocaleDateString()}</p>
                <select
                  value={o.status}
                  onChange={e => handleStatusUpdate(o._id, e.target.value)}
                  style={{ ...styles.statusSelect, borderColor: statusColor(o.status), color: statusColor(o.status) }}
                >
                  {['pending', 'processing', 'shipped', 'delivered', 'cancelled'].map(s => (
                    <option key={s} value={s}>{s.charAt(0).toUpperCase() + s.slice(1)}</option>
                  ))}
                </select>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

const styles = {
  page: { padding: '24px', background: '#f3f3f3', minHeight: '100vh' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px', flexWrap: 'wrap', gap: '16px' },
  title: { margin: 0, fontSize: '28px' },
  stats: { display: 'flex', gap: '16px' },
  stat: { background: '#fff', padding: '12px 20px', borderRadius: '10px', textAlign: 'center', boxShadow: '0 2px 8px rgba(0,0,0,0.07)' },
  statNum: { display: 'block', fontSize: '24px', fontWeight: 'bold', color: '#e94560' },
  statLabel: { fontSize: '12px', color: '#888' },
  tabs: { display: 'flex', gap: '8px', marginBottom: '20px' },
  tab: { padding: '10px 20px', background: '#fff', border: '1px solid #ddd', borderRadius: '8px', cursor: 'pointer', fontSize: '14px' },
  activeTab: { padding: '10px 20px', background: '#e94560', color: '#fff', border: 'none', borderRadius: '8px', cursor: 'pointer', fontSize: '14px', fontWeight: 'bold' },
  section: { background: '#fff', borderRadius: '12px', padding: '24px', boxShadow: '0 2px 8px rgba(0,0,0,0.07)' },
  sectionHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', flexWrap: 'wrap', gap: '12px' },
  seedBtn: { padding: '10px 20px', background: '#1a1a2e', color: '#fff', border: 'none', borderRadius: '8px', cursor: 'pointer', fontSize: '14px', fontWeight: 'bold' },
  deleteAllBtn: { padding: '10px 20px', background: '#f44336', color: '#fff', border: 'none', borderRadius: '8px', cursor: 'pointer', fontSize: '14px', fontWeight: 'bold' },
  msg: { padding: '10px 16px', background: '#f0f9f0', borderRadius: '8px', color: '#2e7d32', marginBottom: '16px' },
  form: { display: 'flex', flexDirection: 'column', gap: '12px' },
  formGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' },
  input: { padding: '10px 14px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '14px' },
  inputFull: { padding: '10px 14px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '14px', width: '100%', boxSizing: 'border-box' },
  textarea: { padding: '10px 14px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '14px', minHeight: '80px', resize: 'vertical' },
  submitBtn: { padding: '12px', background: '#e94560', color: '#fff', border: 'none', borderRadius: '8px', cursor: 'pointer', fontSize: '15px', fontWeight: 'bold' },
  productTable: { display: 'flex', flexDirection: 'column', gap: '10px' },
  productRow: { display: 'flex', alignItems: 'center', gap: '16px', padding: '12px', border: '1px solid #f0f0f0', borderRadius: '8px', background: '#fafafa' },
  thumb: { width: '60px', height: '60px', objectFit: 'cover', borderRadius: '8px' },
  productName: { margin: 0, fontWeight: '600', fontSize: '15px' },
  productCat: { margin: 0, color: '#888', fontSize: '12px' },
  productPrice: { fontWeight: 'bold', color: '#e94560', minWidth: '60px' },
  stockBadge: s => ({ padding: '4px 10px', borderRadius: '20px', fontSize: '12px', background: s > 10 ? '#e8f5e9' : s > 0 ? '#fff3e0' : '#ffebee', color: s > 10 ? '#2e7d32' : s > 0 ? '#e65100' : '#c62828' }),
  delBtn: { padding: '6px 12px', background: '#ffebee', color: '#c62828', border: 'none', borderRadius: '6px', cursor: 'pointer', fontSize: '13px' },
  orderRow: { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', padding: '16px', border: '1px solid #f0f0f0', borderRadius: '8px', marginBottom: '10px', background: '#fafafa', flexWrap: 'wrap', gap: '12px' },
  orderId: { margin: '0 0 4px', fontWeight: 'bold', fontFamily: 'monospace' },
  orderUser: { margin: '0 0 4px', color: '#555', fontSize: '13px' },
  orderItems: { margin: 0, color: '#888', fontSize: '12px' },
  orderRight: { textAlign: 'right' },
  orderTotal: { margin: '0 0 4px', fontWeight: 'bold', color: '#e94560', fontSize: '18px' },
  orderDate: { margin: '0 0 8px', color: '#888', fontSize: '12px' },
  statusSelect: { padding: '6px 12px', borderRadius: '6px', border: '2px solid', fontWeight: 'bold', cursor: 'pointer', background: '#fff' },
};

export default Admin;
